command:
if ( !actor ) {
  ui.notifications.error("Portent macro: Actor not found.");
  return;
}

const roll = await new Roll("1d20").evaluate();

await roll.toMessage({
  speaker: ChatMessage.getSpeaker({ actor }),
  flavor: "Portent Roll"
});

game.modules.get("custom-dnd5e").api.counters.setNumber(actor, "portent", roll.total);
